using Microsoft.VisualStudio.TestTools.UnitTesting;
using Payments;

namespace Payments.Tests;

[TestClass]
public class ChargeTests
{
    private PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup() => _gateway = new PaymentGateway();

    [TestMethod]
    public async Task ChargeAsync_ValidTokenAndAmount_ReturnsSuccessWithChargeId()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 49.99m);

        Assert.IsTrue(result.Success);
        Assert.IsFalse(string.IsNullOrWhiteSpace(result.ChargeId));
    }

    [TestMethod]
    public async Task ChargeAsync_DeclinedCard_ReturnsFailure()
    {
        var result = await _gateway.ChargeAsync("tok_declined", 25.00m);

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_ZeroAmount_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync("tok_valid_visa", 0m));
    }

    [TestMethod]
    public async Task ChargeAsync_NegativeAmount_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync("tok_valid_visa", -10.00m));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public async Task ChargeAsync_NullOrEmptyToken_ThrowsArgumentException(string? token)
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync(token!, 10.00m));
    }

    [TestMethod]
    public async Task ChargeAsync_LargeAmount_ReturnsResult()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 999_999.99m);

        Assert.IsNotNull(result);
    }

    [TestMethod]
    public async Task ChargeAsync_SuccessfulCharge_ReturnsUniqueChargeIds()
    {
        var result1 = await _gateway.ChargeAsync("tok_valid_visa", 10.00m);
        var result2 = await _gateway.ChargeAsync("tok_valid_visa", 20.00m);

        Assert.AreNotEqual(result1.ChargeId, result2.ChargeId);
    }
}

[TestClass]
public class RefundTests
{
    private PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup() => _gateway = new PaymentGateway();

    [TestMethod]
    public async Task RefundAsync_ValidChargeId_ReturnsSuccessWithRefundId()
    {
        var result = await _gateway.RefundAsync("ch_valid_123");

        Assert.IsTrue(result.Success);
        Assert.IsFalse(string.IsNullOrWhiteSpace(result.RefundId));
    }

    [TestMethod]
    public async Task RefundAsync_InvalidChargeId_ReturnsFailure()
    {
        var result = await _gateway.RefundAsync("ch_nonexistent");

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public async Task RefundAsync_NullOrEmptyChargeId_ThrowsArgumentException(string? chargeId)
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.RefundAsync(chargeId!));
    }

    [TestMethod]
    public async Task RefundAsync_AlreadyRefundedCharge_ReturnsFailure()
    {
        // First refund should succeed
        var first = await _gateway.RefundAsync("ch_already_refunded");

        // Second refund of the same charge should fail
        var second = await _gateway.RefundAsync("ch_already_refunded");

        Assert.IsFalse(second.Success);
    }
}

